import{_ as a,o as d,c as e,a5 as r}from"./chunks/framework.DYHZIppx.js";const p=JSON.parse('{"title":"Decision Log","description":"","frontmatter":{},"headers":[],"relativePath":"decision-log/index.md","filePath":"decision-log/index.md"}'),i={name:"decision-log/index.md"};function o(n,t,s,h,l,c){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="decision-log" tabindex="-1">Decision Log <a class="header-anchor" href="#decision-log" aria-label="Permalink to &quot;Decision Log&quot;">​</a></h1><p>이 섹션은 <code>rest-domain-state-manager</code> 설계 과정에서 내린 주요 아키텍처 결정과 구체적인 구현 의사결정들을 기록합니다.</p><p>모든 라이브러리는 수많은 트레이드오프의 산물입니다. 각 결정이 <strong>왜</strong> 이루어졌는지, 어떤 대안이 검토되었고 어떤 이유로 기각되었는지를 투명하게 공개함으로써, 미래의 기여자와 사용자가 설계 의도를 정확히 파악할 수 있도록 합니다.</p><hr><h2 id="아키텍처-결정-레코드-ard" tabindex="-1">아키텍처 결정 레코드 (ARD) <a class="header-anchor" href="#아키텍처-결정-레코드-ard" aria-label="Permalink to &quot;아키텍처 결정 레코드 (ARD)&quot;">​</a></h2><p>ARD는 큰 방향성을 결정하는 상위 문서입니다.</p><table tabindex="0"><thead><tr><th>ID</th><th>날짜</th><th>제목</th><th>상태</th></tr></thead><tbody><tr><td><a href="/rest-domain-state-manager/decision-log/ard-0000.html">ARD-0000</a></td><td>2026-03-18</td><td>아키텍처 진단 및 초기 설계 방향</td><td>완료</td></tr><tr><td><a href="/rest-domain-state-manager/decision-log/ard-0001.html">ARD-0001</a></td><td>2026-03-20</td><td>V8 최적화 정렬 및 2026 아키텍처 동향 반영</td><td>완료</td></tr></tbody></table><hr><h2 id="구현-의사결정-impl" tabindex="-1">구현 의사결정 (IMPL) <a class="header-anchor" href="#구현-의사결정-impl" aria-label="Permalink to &quot;구현 의사결정 (IMPL)&quot;">​</a></h2><p>ARD 하위의 구체적인 구현 결정을 기록합니다. 각 문서는 하나의 소주제에 집중하며, 변경 근거와 엣지 케이스 분석을 포함합니다.</p><table tabindex="0"><thead><tr><th>ID</th><th>날짜</th><th>제목</th><th>상위 ARD</th></tr></thead><tbody><tr><td><a href="/rest-domain-state-manager/decision-log/impl-dirty-fields.html">IMPL-001</a></td><td>2026-03-20</td><td>Dirty Checking 기반 HTTP 분기 알고리즘</td><td>ARD-0001</td></tr><tr><td><a href="/rest-domain-state-manager/decision-log/impl-optimistic-rollback.html">IMPL-002</a></td><td>2026-03-20</td><td>Optimistic Update 롤백 메커니즘</td><td>ARD-0001</td></tr><tr><td><a href="/rest-domain-state-manager/decision-log/impl-microtask-batching.html">IMPL-003</a></td><td>2026-03-20</td><td>Microtask 기반 브로드캐스트 배칭</td><td>ARD-0001</td></tr><tr><td><a href="/rest-domain-state-manager/decision-log/impl-src-layout.html">IMPL-004</a></td><td>2026-03-20</td><td>소스 디렉토리 구조 재편</td><td>ARD-0001</td></tr><tr><td><a href="/rest-domain-state-manager/decision-log/impl-cicd-pipeline.html">IMPL-005</a></td><td>2026-03-23</td><td>CI/CD 파이프라인 구축</td><td>ARD-0001</td></tr></tbody></table><hr><h2 id="이-기록이-존재하는-이유" tabindex="-1">이 기록이 존재하는 이유 <a class="header-anchor" href="#이-기록이-존재하는-이유" aria-label="Permalink to &quot;이 기록이 존재하는 이유&quot;">​</a></h2><p>소프트웨어는 설계 과정의 흔적을 남기지 않습니다. 코드는 <strong>현재</strong> 상태만 보여주지, <strong>왜</strong> 그렇게 되었는지는 말하지 않습니다. 6개월 후 같은 문제를 다시 마주쳤을 때 이미 검토하고 기각했던 아이디어를 또 검토하는 비효율을 막기 위해, 그리고 이 프로젝트를 포트폴리오로 검토하는 사람이 단순히 코드 결과물이 아니라 사고 과정을 볼 수 있도록 이 기록을 공개합니다.</p>',14)])])}const g=a(i,[["render",o]]);export{p as __pageData,g as default};
